<div class="d-flex justify-content-between align-items-center mb-4"><div><p class="text-uppercase fw-semibold archive-kicker-dark mb-1">Inbox</p><h1 class="h2 mb-0">Notifications</h1></div><div class="d-flex gap-2"><a class="btn btn-outline-dark" href="<?= e(url('/notifications/preferences')) ?>">Preferences</a><form method="post" action="<?= e(url('/notifications/read-all')) ?>"><button class="btn btn-outline-secondary">Mark all read</button></form></div></div>
<?php if ($notifications === []): ?><div class="archive-card p-4 text-muted">No notifications yet.</div><?php else: ?><div class="row g-2"><?php foreach ($notifications as $notification): ?><div class="col-12"><div class="archive-card p-3 <?= empty($notification['read_at']) ? 'border border-warning' : '' ?>"><div class="d-flex justify-content-between gap-3"><div><strong><?= e($notification['title']) ?></strong><?php if (empty($notification['read_at'])): ?> <span class="badge text-bg-warning">New</span><?php endif; ?><div><?= e($notification['body']) ?></div><div class="small text-muted"><?= e($notification['created_at']) ?><?= !empty($notification['emailed_at']) ? ' | Email sent' : '' ?></div></div><?php if (!empty($notification['action_url'])): ?><form method="post" action="<?= e(url('/notifications/read?id=' . (int) $notification['id'])) ?>"><input type="hidden" name="target" value="<?= e($notification['action_url']) ?>"><button class="btn btn-sm btn-archive">Open</button></form><?php elseif (empty($notification['read_at'])): ?><form method="post" action="<?= e(url('/notifications/read?id=' . (int) $notification['id'])) ?>"><button class="btn btn-sm btn-outline-secondary">Mark read</button></form><?php endif; ?></div></div></div><?php endforeach; ?></div><?php endif; ?>
